"""
Pytest test suite for Encounter creation requirements.

Requirement: A clinician shall create an Encounter for a patient with start and end
timestamps; end before start shall be rejected. Negative paths including permission
denial, missing mandatory elements, and conflicting state transitions must be tested.
"""

import pytest
from datetime import datetime, timedelta, timezone
from unittest.mock import MagicMock, patch
from dataclasses import dataclass, field
from enum import Enum
from typing import Optional
import uuid


# ---------------------------------------------------------------------------
# Domain model stubs – replace with real imports from your application
# ---------------------------------------------------------------------------

class EncounterStatus(str, Enum):
    PLANNED = "planned"
    IN_PROGRESS = "in-progress"
    FINISHED = "finished"
    CANCELLED = "cancelled"
    ENTERED_IN_ERROR = "entered-in-error"


class UserRole(str, Enum):
    CLINICIAN = "clinician"
    NURSE = "nurse"
    ADMIN = "admin"
    PATIENT = "patient"
    BILLING = "billing"


@dataclass
class User:
    user_id: str
    role: UserRole
    is_active: bool = True
    assigned_patient_ids: list = field(default_factory=list)


@dataclass
class Patient:
    patient_id: str
    is_active: bool = True


@dataclass
class EncounterCreateRequest:
    patient_id: str
    start: Optional[datetime] = None
    end: Optional[datetime] = None
    status: EncounterStatus = EncounterStatus.PLANNED
    reason: Optional[str] = None
    practitioner_id: Optional[str] = None


@dataclass
class Encounter:
    encounter_id: str
    patient_id: str
    start: datetime
    end: Optional[datetime]
    status: EncounterStatus
    reason: Optional[str]
    practitioner_id: str
    created_by: str


# ---------------------------------------------------------------------------
# Custom exceptions – replace with real imports
# ---------------------------------------------------------------------------

class PermissionDeniedError(Exception):
    """Raised when the requesting user lacks sufficient privileges."""


class ValidationError(Exception):
    """Raised when a request fails validation rules."""


class ConflictError(Exception):
    """Raised when the requested state transition is not allowed."""


class PatientNotFoundError(Exception):
    """Raised when the target patient does not exist."""


class EncounterNotFoundError(Exception):
    """Raised when the target encounter does not exist."""


# ---------------------------------------------------------------------------
# Service under test (stub) – replace with real import
# ---------------------------------------------------------------------------

class EncounterService:
    """
    Stub service.  In a real project this would be imported from the
    application layer.  The stub is here only to make the tests runnable
    without the full application stack; swap it out for the real class.
    """

    ALLOWED_ROLES = {UserRole.CLINICIAN, UserRole.NURSE}

    # Roles that may *read* but never *write* encounters
    READ_ONLY_ROLES = {UserRole.PATIENT, UserRole.BILLING}

    def __init__(self, encounter_repository, patient_repository, auth_service):
        self._encounters = encounter_repository
        self._patients = patient_repository
        self._auth = auth_service

    # ------------------------------------------------------------------
    # Public API
    # ------------------------------------------------------------------

    def create_encounter(
        self, requesting_user: User, request: EncounterCreateRequest
    ) -> Encounter:
        self._check_permission(requesting_user)
        self._validate_patient(request.patient_id)
        self._validate_required_fields(request)
        self._validate_timestamps(request)

        encounter = Encounter(
            encounter_id=str(uuid.uuid4()),
            patient_id=request.patient_id,
            start=request.start,
            end=request.end,
            status=request.status,
            reason=request.reason,
            practitioner_id=request.practitioner_id or requesting_user.user_id,
            created_by=requesting_user.user_id,
        )
        self._encounters.save(encounter)
        return encounter

    def update_encounter_status(
        self,
        requesting_user: User,
        encounter_id: str,
        new_status: EncounterStatus,
    ) -> Encounter:
        self._check_permission(requesting_user)
        encounter = self._encounters.get(encounter_id)
        if encounter is None:
            raise EncounterNotFoundError(encounter_id)
        self._validate_status_transition(encounter.status, new_status)
        encounter.status = new_status
        self._encounters.save(encounter)
        return encounter

    # ------------------------------------------------------------------
    # Private helpers
    # ------------------------------------------------------------------

    def _check_permission(self, user: User):
        if not user.is_active:
            raise PermissionDeniedError("User account is inactive.")
        if user.role not in self.ALLOWED_ROLES:
            raise PermissionDeniedError(
                f"Role '{user.role}' is not permitted to create or modify encounters."
            )

    def _validate_patient(self, patient_id: str):
        patient = self._patients.get(patient_id)
        if patient is None:
            raise PatientNotFoundError(patient_id)
        if not patient.is_active:
            raise ValidationError(f"Patient '{patient_id}' is not active.")

    def _validate_required_fields(self, request: EncounterCreateRequest):
        missing = []
        if not request.patient_id:
            missing.append("patient_id")
        if request.start is None:
            missing.append("start")
        if missing:
            raise ValidationError(f"Missing mandatory field(s): {', '.join(missing)}")

    def _validate_timestamps(self, request: EncounterCreateRequest):
        if request.end is not None and request.start is not None:
            if request.end < request.start:
                raise ValidationError(
                    "Encounter end timestamp must not be before start timestamp."
                )
            if request.end == request.start:
                raise ValidationError(
                    "Encounter end timestamp must be after start timestamp."
                )

    # Allowed state-machine transitions
    _VALID_TRANSITIONS = {
        EncounterStatus.PLANNED: {
            EncounterStatus.IN_PROGRESS,
            EncounterStatus.CANCELLED,
        },
        EncounterStatus.IN_PROGRESS: {
            EncounterStatus.FINISHED,
            EncounterStatus.CANCELLED,
        },
        EncounterStatus.FINISHED: {EncounterStatus.ENTERED_IN_ERROR},
        EncounterStatus.CANCELLED: {EncounterStatus.ENTERED_IN_ERROR},
        EncounterStatus.ENTERED_IN_ERROR: set(),
    }

    def _validate_status_transition(
        self, current: EncounterStatus, new: EncounterStatus
    ):
        allowed = self._VALID_TRANSITIONS.get(current, set())
        if new not in allowed:
            raise ConflictError(
                f"Transition from '{current}' to '{new}' is not permitted."
            )


