class TestCreateEncounterHappyPath:
    """Positive scenarios: valid input from authorised users."""

    def test_clinician_creates_encounter_with_start_and_end(
        self, service, clinician, valid_request
    ):
        encounter = service.create_encounter(clinician, valid_request)

        assert encounter.encounter_id is not None
        assert encounter.patient_id == valid_request.patient_id
        assert encounter.start == valid_request.start
        assert encounter.end == valid_request.end
        assert encounter.created_by == clinician.user_id

    def test_nurse_creates_encounter_successfully(
        self, service, nurse, valid_request
    ):
        encounter = service.create_encounter(nurse, valid_request)
        assert encounter is not None
        assert encounter.created_by == nurse.user_id

    def test_encounter_without_end_timestamp_is_accepted(
        self, service, clinician, active_patient, now
    ):
        """An open-ended encounter (no end timestamp) is valid."""
        request = EncounterCreateRequest(
            patient_id=active_patient.patient_id,
            start=now,
            end=None,
        )
        encounter = service.create_encounter(clinician, request)
        assert encounter.end is None

    def test_encounter_persisted_to_repository(
        self, service, clinician, valid_request, mock_encounter_repo
    ):
        service.create_encounter(clinician, valid_request)
        mock_encounter_repo.save.assert_called_once()

    def test_encounter_id_is_unique_across_calls(
        self, service, clinician, valid_request
    ):
        enc1 = service.create_encounter(clinician, valid_request)
        enc2 = service.create_encounter(clinician, valid_request)
        assert enc1.encounter_id != enc2.encounter_id

    def test_encounter_reason_is_stored(
        self, service, clinician, valid_request
    ):
        valid_request.reason = "Acute pain assessment"
        encounter = service.create_encounter(clinician, valid_request)
        assert encounter.reason == "Acute pain assessment"


