class TestTimestampValidation:
    """Tests specifically targeting the start/end timestamp constraint."""

    def test_end_before_start_raises_validation_error(
        self, service, clinician, active_patient, now
    ):
        request = EncounterCreateRequest(
            patient_id=active_patient.patient_id,
            start=now,
            end=now - timedelta(seconds=1),
        )
        with pytest.raises(ValidationError, match="end timestamp must not be before"):
            service.create_encounter(clinician, request)

    def test_end_equal_to_start_raises_validation_error(
        self, service, clinician, active_patient, now
    ):
        request = EncounterCreateRequest(
            patient_id=active_patient.patient_id,
            start=now,
            end=now,
        )
        with pytest.raises(ValidationError, match="end timestamp must be after"):
            service.create_encounter(clinician, request)

    def test_end_one_second_before_start_rejected(
        self, service, clinician, active_patient, now
    ):
        request = EncounterCreateRequest(
            patient_id=active_patient.patient_id,
            start=now,
            end=now - timedelta(seconds=1),
        )
        with pytest.raises(ValidationError):
            service.create_encounter(clinician, request)

    def test_end_one_day_before_start_rejected(
        self, service, clinician, active_patient, now
    ):
        request = EncounterCreateRequest(
            patient_id=active_patient.patient_id,
            start=now,
            end=now - timedelta(days=1),
        )
        with pytest.raises(ValidationError):
            service.create_encounter(clinician, request)

    def test_end_far_in_future_accepted(
        self, service, clinician, active_patient, now
    ):
        request = EncounterCreateRequest(
            patient_id=active_patient.patient_id,
            start=now,
            end=now + timedelta(days=365),
        )
        encounter = service.create_encounter(clinician, request)
        assert encounter.end > encounter.start

    def test_encounter_not_saved_when_end_before_start(
        self, service, clinician, active_patient, now, mock_encounter_repo
    ):
        """Repository must not be called when validation fails."""
        request = EncounterCreateRequest(
            patient_id=active_patient.patient_id,
            start=now,
            end=now - timedelta(minutes=5),
        )
        with pytest.raises(ValidationError):
            service.create_encounter(clinician, request)
        mock_encounter_repo.save.assert_not_called()

    @pytest.mark.parametrize("delta_seconds", [-3600, -1, 0])
    def test_invalid_end_offsets_are_rejected(
        self, service, clinician, active_patient, now, delta_seconds
    ):
        request = EncounterCreateRequest(
            patient_id=active_patient.patient_id,
            start=now,
            end=now + timedelta(seconds=delta_seconds),
        )
        with pytest.raises(ValidationError):
            service.create_encounter(clinician, request)

    @pytest.mark.parametrize("delta_seconds", [1, 60, 3600, 86400])
    def test_valid_end_offsets_are_accepted(
        self, service, clinician, active_patient, now, delta_seconds
    ):
        request = EncounterCreateRequest(
            patient_id=active_patient.patient_id,
            start=now,
            end=now + timedelta(seconds=delta_seconds),
        )
        encounter = service.create_encounter(clinician, request)
        assert encounter is not None


