class TestPermissionDenial:
    """Users without the correct role must be rejected."""

    def test_admin_cannot_create_encounter(
        self, service, admin_user, valid_request
    ):
        with pytest.raises(PermissionDeniedError, match="not permitted"):
            service.create_encounter(admin_user, valid_request)

    def test_patient_role_cannot_create_encounter(
        self, service, patient_user, valid_request
    ):
        with pytest.raises(PermissionDeniedError):
            service.create_encounter(patient_user, valid_request)

    def test_billing_role_cannot_create_encounter(
        self, service, billing_user, valid_request
    ):
        with pytest.raises(PermissionDeniedError):
            service.create_encounter(billing_user, valid_request)

    def test_inactive_clinician_cannot_create_encounter(
        self, service, inactive_clinician, valid_request
    ):
        with pytest.raises(PermissionDeniedError, match="inactive"):
            service.create_encounter(inactive_clinician, valid_request)

