class TestStateTransitions:
    """State machine: only defined transitions must succeed."""

    # ---- valid transitions ------------------------------------------------

    def test_planned_to_in_progress_is_allowed(
        self, service, clinician, existing_encounter
    ):
        existing_encounter.status = EncounterStatus.PLANNED
        result = service.update_encounter_status(
            clinician, existing_encounter.encounter_id, EncounterStatus.IN_PROGRESS
        )
        assert result.status == EncounterStatus.IN_PROGRESS

    def test_planned_to_cancelled_is_allowed(
        self, service, clinician, existing_encounter
    ):
        existing_encounter.status = EncounterStatus.PLANNED
        result = service.update_encounter_status(
            clinician, existing_encounter.encounter_id, EncounterStatus.CANCELLED
        )
        assert result.status == EncounterStatus.CANCELLED

    def test_in_progress_to_finished_is_allowed(
        self, service, clinician, existing_encounter
    ):
        existing_encounter.status = EncounterStatus.IN_PROGRESS
        result = service.update_encounter_status(
            clinician, existing_encounter.encounter_id, EncounterStatus.FINISHED
        )
        assert result.status == EncounterStatus.FINISHED

    def test_finished_to_entered_in_error_is_allowed(
        self, service, clinician, existing_encounter
    ):
        existing_encounter.status = EncounterStatus.FINISHED
        result = service.update_encounter_status(
            clinician, existing_encounter.encounter_id, EncounterStatus.ENTERED_IN_ERROR
        )
        assert result.status == EncounterStatus.ENTERED_IN_ERROR

    # ---- invalid transitions ----------------------------------------------

    def test_finished_to_in_progress_is_rejected(
        self, service, clinician, existing_encounter
    ):
        existing_encounter.status = EncounterStatus.FINISHED
        with pytest.raises(ConflictError):
            service.update_encounter_status(
                clinician, existing_encounter.encounter_id, EncounterStatus.IN_PROGRESS
            )

    def test_finished_to_planned_is_rejected(
        self, service, clinician, existing_encounter
    ):
        existing_encounter.status = EncounterStatus.FINISHED
        with pytest.raises(ConflictError):
            service.update_encounter_status(
                clinician, existing_encounter.encounter_id, EncounterStatus.PLANNED
            )

    def test_cancelled_to_in_progress_is_rejected(
        self, service, clinician, existing_encounter
    ):
        existing_encounter.status = EncounterStatus.CANCELLED
        with pytest.raises(ConflictError):
            service.update_encounter_status(
                clinician, existing_encounter.encounter_id, EncounterStatus.IN_PROGRESS
            )

    def test_cancelled_to_finished_is_rejected(
        self, service, clinician, existing_encounter
    ):
        existing_encounter.status = EncounterStatus.CANCELLED
        with pytest.raises(ConflictError):
            service.update_encounter_status(
                clinician, existing_encounter.encounter_id, EncounterStatus.FINISHED
            )

    def test_entered_in_error_cannot_transition_to_any_status(
        self, service, clinician, existing_encounter
    ):
        existing_encounter.status = EncounterStatus.ENTERED_IN_ERROR
        for target in EncounterStatus:
            if target == EncounterStatus.ENTERED_IN_ERROR:
                continue   # same-state is not a valid transition either
            with pytest.raises(ConflictError):
                service.update_encounter_status(
                    clinician, existing_encounter.encounter_id, target
                )

    def test_in_progress_to_planned_is_rejected(
        self, service, clinician, existing_encounter
    ):
        existing_encounter.status = EncounterStatus.IN_PROGRESS
        with pytest.raises(ConflictError):
            service.update_encounter_status(
                clinician, existing_encounter.encounter_id, EncounterStatus.PLANNED
            )

    def test_update_nonexistent_encounter_raises_not_found(
        self, service, clinician, mock_encounter_repo
    ):
        mock_encounter_repo.get.return_value = None
        with pytest.raises(EncounterNotFoundError):
            service.update_encounter_status(
                clinician, "enc-does-not-exist", EncounterStatus.IN_PROGRESS
            )

    def test_unauthorised_user_cannot_update_status(
        self, service, admin_user, existing_encounter
    ):
        existing_encounter.status = EncounterStatus.PLANNED
        with pytest.raises(PermissionDeniedError):
            service.update_encounter_status(
                admin_user, existing_encounter.encounter_id, EncounterStatus.IN_PROGRESS
            )

    @pytest.mark.parametrize("from_status,to_status", [
        (EncounterStatus.FINISHED,        EncounterStatus.PLANNED),
        (EncounterStatus.FINISHED,        EncounterStatus.IN_PROGRESS),
        (EncounterStatus.FINISHED,        EncounterStatus.CANCELLED),
        (EncounterStatus.CANCELLED,       EncounterStatus.PLANNED),
        (EncounterStatus.CANCELLED,       EncounterStatus.IN_PROGRESS),
        (EncounterStatus.ENTERED_IN_ERROR, EncounterStatus.PLANNED),
        (EncounterStatus.ENTERED_IN_ERROR, EncounterStatus.IN_PROGRESS),
        (EncounterStatus.ENTERED_IN_ERROR, EncounterStatus.FINISHED),
        (EncounterStatus.ENTERED_IN_ERROR, EncounterStatus.CANCELLED),
    ])
    def test_parametrised_invalid_transitions(
        self, service, clinician, existing_encounter, from_status, to_status
    ):
        existing_encounter.status = from_status
        with pytest.raises(ConflictError):
            service.update_encounter_status(
                clinician, existing_encounter.encounter_id, to_status
            )
